import { v4 as uuidv4 } from 'uuid';
import authService from "src/auth/auth.service";
import StatusDrop from "src/utils/StatusDrop";
import { epochTogmt } from 'src/utils/Common';
import { Link } from 'react-router-dom';
import StatusDetails from 'src/utils/StatusDetails';

export const tablSignUpCodeConstant = (fetchSignUpCodeList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Email",
            selector: (row) => row?.email,
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Generate Code",
            selector: (row) => row?.code
        },
        {
            id: 3,
            name: "Create Time",
            selector: (row) =>row?.createTime ? epochTogmt(row.createTime) : '-'
        },
        {
            id: 4,
            name: "Validity Time",
            selector: (row) => row?.validity !== 0 ? epochTogmt(row.validity) : "-"
        },
        {
            id: 5,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.codeStatus} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 6,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.codeStatus}
                        type={'SIGN_UP_CODE'}
                        action={fetchSignUpCodeList}
                        key={uuidv4()}
                        publishPermission={"SIGN_UP_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 7,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.codeStatus === "ENABLED" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
